-- -- Tabel structuur voor tabel mailtabel-- CREATE TABLE mailtabel (  mail_id int(11) NOT NULL auto_increment,  zoeknummer varchar(16) NOT NULL default '0',  mailtijd datetime NOT NULL default '0000-00-00 00:00:00',  naaradres varchar(40) NOT NULL default '',  vanadres varchar(40) NOT NULL default '',  verzendtitel varchar(50) NOT NULL default '',  persoon_id tinyint(3) NOT NULL default '0',  verzondenjn tinyint(3) NOT NULL default '0',  mailtxt blob NOT NULL,  PRIMARY KEY  (mail_id),  KEY persoon_id (persoon_id),  KEY naaradres (naaradres),  KEY zoeknummer (zoeknummer)) TYPE=MyISAM AUTO_INCREMENT=1046 ;-- -- Gegevens worden uitgevoerd voor tabel mailtabel-- 